if (_gateways.contains(msg.sender) && !tracker.receivedBy[msg.sender]) {
    // Count number of time received
    tracker.receivedBy[msg.sender] = true;
    ++tracker.countReceived;
    emit Received(id, msg.sender);

    // if already executed, leave gracefully
    if (tracker.executed) return IERC7786Recipient.receiveMessage.selector;
} else if (tracker.executed) {
    revert ERC7786OpenBridgeAlreadyExecuted();
}

validationData = SignatureChecker
            .isValidSignatureNow(
                oracle,
                _hashTypedDataV4(
                    keccak256(abi.encode(TOKEN_PRICE_TYPEHASH, token, validAfter, validUntil, tokenPrice))
                ),
                paymasterData[0x56:0x56 + uint16(bytes2(paymasterData[0x54:0x56]))]
            )
            .packValidationData(validAfter, validUntil);

if (_pendingCommandIds.get(uint256(commandId))) {
            _pendingCommandIds.unset(uint256(commandId));

            emit IBaseAmplifierGateway.MessageExecuted(commandId);

            return
                commandId ==
                keccak256(abi.encode(sourceChain, sourceAddress, msg.sender.toChecksumHexString(), payloadHash));
        } else return false;

for (uint256 i = 0; i < targets.length; ++i) {
    (bool controlled, bool withDelay, uint32 nonce) = _getManagerData(plan, i);
    if (controlled) {
        uint32 executedNonce = $._manager.execute{value: values[i]}(targets[i], calldatas[i]);
        if (withDelay && executedNonce != nonce) {
            revert GovernorMismatchedNonce(proposalId, nonce, executedNonce);
        }
    } else {
        (bool success, bytes memory returndata) = targets[i].call{value: values[i]}(calldatas[i]);
        Address.verifyCallResult(success, returndata);
    }
}

if (from == address(0)) {
    uint256 totalMintValue = 0;
    for (uint256 i = 0; i < ids.length; ++i) {
        uint256 value = values.unsafeMemoryAccess(i);
        // Overflow check required: The rest of the code assumes that totalSupply never overflows
        $._totalSupply[ids.unsafeMemoryAccess(i)] += value;
        totalMintValue += value;
    }
    // Overflow check required: The rest of the code assumes that totalSupplyAll never overflows
    $._totalSupplyAll += totalMintValue;
}

unchecked {
    if (data.length < 0x20) return (false, data);
    uint256 offset = uint256(_unsafeReadBytesOffset(data, 0));
    if (data.length - 0x20 < offset) return (false, data);
    uint256 length = uint256(_unsafeReadBytesOffset(data, offset));
    if (data.length - 0x20 - offset < length) return (false, data);
    Bytes.splice(data, 0x20 + offset, 0x20 + offset + length);
    return (true, data);
}

if (range1 == range2) {
    bool success = aggregator1 == address(uint160(SIG_VALIDATION_SUCCESS)) &&
        aggregator2 == address(uint160(SIG_VALIDATION_SUCCESS));
    uint48 validAfter = uint48(Math.max(validAfter1, validAfter2));
    uint48 validUntil = uint48(Math.min(validUntil1, validUntil2));
    return packValidationData(success, validAfter, validUntil, range1);
} else {
    return SIG_VALIDATION_FAILED;
}

if (
    SignatureChecker.isValidSignatureNow(
        voter,
        _hashTypedDataV4(
            keccak256(
                abi.encode(BALLOT_TYPEHASH, proposalId, support, voter, nonces(voter, uint192(proposalId)))
            )
        ),
        signature
    )
) {
    _useNonce(voter, uint192(proposalId));
    return true;
} else {
    return super._validateVoteSig(proposalId, support, voter, signature);
}

for (uint256 i = 0; i < targets.length; ++i) {
    (bool controlled, bool withDelay, uint32 nonce) = _getManagerData(plan, i);
    if (controlled) {
        uint32 executedNonce = _manager.execute{value: values[i]}(targets[i], calldatas[i]);
        if (withDelay && executedNonce != nonce) {
            revert GovernorMismatchedNonce(proposalId, nonce, executedNonce);
        }
    } else {
        (bool success, bytes memory returndata) = targets[i].call{value: values[i]}(calldatas[i]);
        Address.verifyCallResult(success, returndata);
    }
}

if (src != dst && amount > 0) {
    if (src != address(0)) {
        (uint256 oldWeight, uint256 newWeight) = _writeCheckpoint(_checkpoints[src], _subtract, amount);
        emit DelegateVotesChanged(src, oldWeight, newWeight);
    }

    if (dst != address(0)) {
        (uint256 oldWeight, uint256 newWeight) = _writeCheckpoint(_checkpoints[dst], _add, amount);
        emit DelegateVotesChanged(dst, oldWeight, newWeight);
    }
}

try IERC1822Proxiable(newImplementation).proxiableUUID() returns (bytes32 slot) {
    if (slot != ERC1967Utils.IMPLEMENTATION_SLOT) {
        revert UUPSUnsupportedProxiableUUID(slot);
    }
    ERC1967Utils.upgradeToAndCall(newImplementation, data);
} catch {
    // The implementation is not UUPS
    revert ERC1967Utils.ERC1967InvalidImplementation(newImplementation);
}

if (to != address(0)) {
    address operator = _msgSender();
    if (batch) {
        ERC1155Utils.checkOnERC1155BatchReceived(operator, from, to, ids, values, data);
    } else {
        uint256 id = ids.unsafeMemoryAccess(0);
        uint256 value = values.unsafeMemoryAccess(0);
        ERC1155Utils.checkOnERC1155Received(operator, from, to, id, value, data);
    }
}

if (from == address(0)) {
    uint256 totalMintValue = 0;
    for (uint256 i = 0; i < ids.length; ++i) {
        uint256 value = values.unsafeMemoryAccess(i);
        // Overflow check required: The rest of the code assumes that totalSupply never overflows
        _totalSupply[ids.unsafeMemoryAccess(i)] += value;
        totalMintValue += value;
    }
    // Overflow check required: The rest of the code assumes that totalSupplyAll never overflows
    _totalSupplyAll += totalMintValue;
}

if (emitEvent || auth != address(0)) {
    address owner = _requireOwned(tokenId);

    // We do not use _isAuthorized because single-token approvals should not be able to call approve
    if (auth != address(0) && owner != auth && !isApprovedForAll(owner, auth)) {
        revert ERC721InvalidApprover(auth);
    }

    if (emitEvent) {
        emit Approval(owner, to, tokenId);
    }
}

if (signature.length == 65) {
    bytes32 r;
    bytes32 s;
    uint8 v;
    // ecrecover takes the signature parameters, and the only way to get them
    // currently is to use assembly.
    assembly ("memory-safe") {
        r := mload(add(signature, 0x20))
        s := mload(add(signature, 0x40))
        v := byte(0, mload(add(signature, 0x60)))
    }
    return tryRecover(hash, v, r, s);
} else {
    return (address(0), RecoverError.InvalidSignatureLength, bytes32(signature.length));
}

if (signature.length == 65) {
    bytes32 r;
    bytes32 s;
    uint8 v;
    // ecrecover takes the signature parameters, calldata slices would work here, but are
    // significantly more expensive (length check) than using calldataload in assembly.
    assembly ("memory-safe") {
        r := calldataload(signature.offset)
        s := calldataload(add(signature.offset, 0x20))
        v := byte(0, calldataload(add(signature.offset, 0x40)))
    }
    return tryRecover(hash, v, r, s);
} else {
    return (address(0), RecoverError.InvalidSignatureLength, bytes32(signature.length));
}

if (signer.length < 20) {
    return false;
} else if (signer.length == 20) {
    return isValidSignatureNow(address(bytes20(signer)), hash, signature);
} else {
    (bool success, bytes memory result) = address(bytes20(signer)).staticcall(
        abi.encodeCall(IERC7913SignatureVerifier.verify, (signer.slice(20), hash, signature))
    );
    return (success &&
        result.length >= 32 &&
        abi.decode(result, (bytes32)) == bytes32(IERC7913SignatureVerifier.verify.selector));
}

return
            hash == appSeparator.toTypedDataHash(contentsHash) &&
            bytes(contentsDescr).length != 0 &&
            _rawSignatureValidation(
                appSeparator.toTypedDataHash(
                    ERC7739Utils.typedDataSignStructHash(
                        contentsDescr,
                        contentsHash,
                        abi.encode(keccak256(bytes(name)), keccak256(bytes(version)), chainId, verifyingContract, salt)
                    )
                ),
                signature
            );

assembly ("memory-safe") {
    success := and(
        // clientDataJson.length >= typeIndex + 21
        gt(mload(clientDataJSON), add(typeIndex, 20)),
        eq(
            // get 32 bytes starting at index typexIndex in clientDataJSON, and keep the leftmost 21 bytes
            and(mload(add(add(clientDataJSON, 0x20), typeIndex)), shl(88, not(0))),
            // solhint-disable-next-line quotes
            '"type":"webauthn.get"'
        )
    )
}

assembly ("memory-safe") {
    let dataPtr := add(result, 0x20)
    // Write result on top of args to avoid allocating extra memory.
    success := staticcall(gas(), 0x05, dataPtr, mload(result), dataPtr, mLen)
    // Overwrite the length.
    // result.length > returndatasize() is guaranteed because returndatasize() == m.length
    mstore(result, mLen)
    // Set the memory pointer after the returned data.
    mstore(0x40, add(dataPtr, mLen))
}

for (uint256 currentOffset = listOffset; currentOffset < itemLength; ptr += 0x20) {
    (uint256 elementOffset, uint256 elementLength, ) = _decodeLength(item.slice(currentOffset));
    Memory.Slice element = item.slice(currentOffset, elementLength + elementOffset);
    currentOffset += elementOffset + elementLength;

    // Write item to the buffer
    assembly ("memory-safe") {
        mstore(ptr, element)
    }
}
